# Dictionnaire inverse ru→ing (mots simples)
DICT_RU_ING = {v.split(',')[0].strip().lower(): k for k, v in DICT_ING_RU.items() if len(v.split(',')[0].strip()) < 20}

# Mots français courants
DICT_FR_ING = {
    'bonjour': 'маьрша хиллалц', 'salut': 'маьрша хиллалц', 'merci': 'баркал',
    'oui': 'хIаъ', 'non': 'ца хилар', 'eau': 'хи', 'maison': 'цIа',
    'mère': 'нана', 'père': 'да', 'frère': 'воша', 'sœur': 'йиша',
    'montagne': 'лоам', 'paix': 'маьрша', 'bien': 'дика', 'tête': 'корта',
    'main': 'куьг', 'oeil': 'бIаьрг', 'dent': 'цIогI', 'oreille': 'лерг',
    'aujourd\'hui': 'тахан', 'demain': 'кхана', 'maintenant': 'хинца',
    'ami': 'доттагI', 'frère': 'воша', 'liberté': 'маьрша хилар',
}


def lookup(text: str) -> str | None:
    t = text.strip().lower()
    if t in DICT_ING_RU:
        return f"🏔 {DICT_ING_RU[t]}"
    if t in DICT_RU_ING:
        return f"🏔 {DICT_RU_ING[t]}"
    if t in DICT_FR_ING:
        return f"🏔 {DICT_FR_ING[t]}"
    return None


async def translate_claude(text: str) -> str:
    # Préparer contexte dictionnaire (mots similaires)
    t = text.strip().lower()
    context_words = []
    for k, v in list(DICT_ING_RU.items())[:50]:
        context_words.append(f"{k} = {v}")
    
    prompt = (
        "Tu es un expert en langue ingouche (ГIалгIай мотт), langue nakh caucasique parlée en Ingouchie.\n"
        "Tu connais parfaitement le dictionnaire de Kurdoyev (2005) et Tarieva (2009).\n\n"
        f"Traduis ce texte : « {text} »\n\n"
        "Détecte automatiquement la langue source.\n"
        "Si c'est du français ou du russe → traduis en ingouche (cyrillique).\n"
        "Si c'est de l'ingouche → traduis en français ET en russe.\n\n"
        "Réponds UNIQUEMENT avec ce format, sans aucune explication :\n"
        "🏔 [ingouche]\n"
        "🇷🇺 [russe]\n"
        "🇫🇷 [français]"
    )

    async with httpx.AsyncClient() as client:
        resp = await client.post(
            "https://api.anthropic.com/v1/messages",
            headers={
                "x-api-key": ANTHROPIC_API_KEY,
                "anthropic-version": "2023-06-01",
                "content-type": "application/json",
            },
            json={
                "model": "claude-haiku-4-5-20251001",
                "max_tokens": 200,
                "messages": [{"role": "user", "content": prompt}],
            },
            timeout=30,
        )
        data = resp.json()
        return data["content"][0]["text"].strip()


async def send_message(client: httpx.AsyncClient, chat_id: int, text: str):
    await client.post(
        f"{TELEGRAM_API}/sendMessage",
        json={"chat_id": chat_id, "text": text},
    )


async def poll():
    async with httpx.AsyncClient() as client:
        resp = await client.get(
            f"{TELEGRAM_API}/getUpdates",
            params={"offset": -1, "timeout": 0},
            timeout=10,
        )
        data = resp.json()
        results = data.get("result", [])
        offset = (results[-1]["update_id"] + 1) if results else 0
        logger.info(f"Bot démarré, offset: {offset}, dict: {len(DICT_ING_RU)} mots")

        while True:
            try:
                resp = await client.get(
                    f"{TELEGRAM_API}/getUpdates",
                    params={"offset": offset, "timeout": 30},
                    timeout=40,
                )
                data = resp.json()
                for update in data.get("result", []):
                    offset = update["update_id"] + 1
                    message = update.get("message", {})
                    chat_id = message.get("chat", {}).get("id")
                    text = message.get("text", "")

                    if not chat_id or not text:
                        continue

                    logger.info(f"Message: {text[:50]}")

                    if text.startswith("/start"):
                        reply = (
                            "🌄 Ассаламу алейкум!\n\n"
                            "Je suis le bot de traduction ingouche.\n"
                            "Envoie n'importe quel mot ou phrase en français, russe ou ingouche.\n\n"
                            f"📚 Dictionnaire : {len(DICT_ING_RU):,} mots (Kurdoyev, Tarieva)\n"
                            "🤖 IA : Claude (Anthropic)\n\n"
                            "ГIалгIай мотт 🏔"
                        )
                    elif text.startswith("/aide") or text.startswith("/help"):
                        reply = (
                            "📖 Comment utiliser :\n\n"
                            "• Envoie un mot : нана → mère\n"
                            "• Envoie une phrase : Je vais à la maison\n"
                            "• Ingouche → traduction en FR et RU\n\n"
                            "Exemples :\n"
                            "маьрша → libre, en paix\n"
                            "Bonjour → маьрша хиллалц\n"
                            "корта → tête"
                        )
                    else:
                        # Chercher dans le dictionnaire local d'abord
                        local = lookup(text)
                        if local:
                            reply = local
                            logger.info("Réponse depuis dictionnaire local")
                        else:
                            await send_message(client, chat_id, "⏳")
                            try:
                                reply = await translate_claude(text)
                                logger.info("Réponse depuis Claude")
                            except Exception as e:
                                logger.error(f"Erreur Claude: {e}")
                                reply = "❌ Erreur. Réessaie dans quelques secondes."

                    await send_message(client, chat_id, reply)

            except Exception as e:
                logger.error(f"Erreur polling: {e}")
                await asyncio.sleep(5)


if __name__ == "__main__":
    asyncio.run(poll())
